import{_ as a,o as t,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const l=JSON.parse('{"title":"Meta AEM Acquisition Attribution Coverage","description":"","frontmatter":{"title":"Meta AEM Acquisition Attribution Coverage","slug":"meta-aem-acquisition-attribution-coverage"},"headers":[],"relativePath":"account-hub/meta-aem-acquisition-attribution-coverage.md","filePath":"account-hub/meta-aem-acquisition-attribution-coverage.md"}'),o={name:"account-hub/meta-aem-acquisition-attribution-coverage.md"};function n(s,e,u,c,h,p){return t(),i("div",null,[...e[0]||(e[0]=[r('<p>Branch is expanding our ongoing support for our integration with Meta’s Aggregated Event Measurement (AEM) protocol, which helps you maximize your performance measurement and the value of your campaigns.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Over the past year, Branch has worked closely with Meta to support their enhancements to AEM. These enhancements help marketers with re-engagement optimization, acquisition optimization, and re-engagement attribution.</p><h2 id="what-s-new" tabindex="-1">What&#39;s New? <a class="header-anchor" href="#what-s-new" aria-label="Permalink to &quot;What&#39;s New?&quot;">​</a></h2><p>Branch is expanding our integration with Meta even further by adding support for AEM acquisition attribution – this will give you even deeper insights and empower you to make better data-driven decisions across your acquisition campaigns.</p><p>To achieve optimal attribution coverage with Meta AEM, we recommend enabling our new <a href="./predictive-aggregate-measurement.html">Predictive Aggregate Measurement (PAM)</a> feature, which increases iOS attribution coverage in a privacy-centric manner.</p><h2 id="release-date" tabindex="-1">Release Date <a class="header-anchor" href="#release-date" aria-label="Permalink to &quot;Release Date&quot;">​</a></h2><p>Support for acquisition attribution will start on <strong>November 15, 2024</strong>.</p><p>You will see an increase in your Meta campaign data within the Branch Dashboard, which will allow you to derive more precise insights.</p><p><strong>No action is required</strong> from you to turn this on.</p><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h2><p>To learn more about using Branch with Meta&#39;s AEM protocol, visit our <a href="./enable-app-aggregated-event-measurement-support.html">guide</a>.</p><p>If you have any questions or would like to discuss how this update benefits your team, we encourage you to reach out to your Meta Account team.</p>',13)])])}const d=a(o,[["render",n]]);export{l as __pageData,d as default};
